input.command:
cat << 'EOF' > /tmp/create_conn.sh
#!/bin/bash
curl -s -X POST https://api.hookdeck.com/2025-07-01/connections \
  -H "Authorization: Bearer $HOOKDECK_API_KEY" \
  -H "Content-Type: application/json" \
  -d '{
    "name": "dedup-conn-'$ZEALT_RUN_ID'",
    "source": {
      "name": "dedup-src-'$ZEALT_RUN_ID'"
    },
    "destination": {
      "name": "dedup-dst-'$ZEALT_RUN_ID'",
      "type": "MOCK_API"
    },
    "rules": [
      {
        "type": "deduplicate",
        "window": 300000,
        "include_fields": ["body.id", "body.type"]
      }
    ]
  }'
EOF
bash /tmp/create_conn.sh

